36	export function runScenario(input: unknown): unknown {
37	  const scenario = input as Scenario;
38	  const results = scenario.steps.map((step) => {
39	    const countsByType: Record<string, number> = {};
40	    for (const item of step.items) {
41	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
42	    }
43	    let basePremium = 0;
44	    for (const [type, count] of Object.entries(countsByType)) {
45	      if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
46	        basePremium += COMPONENT_BLOCK_PRICE;
47	      } else {
48	        const perItem = BASE_PREMIUM[type] ?? 0;
49	        basePremium += perItem * count;
50	      }
51	    }
52	    let cursedSurcharge = 0;
53	    for (const item of step.items) {
54	      if (item.cursed) {
55	        cursedSurcharge += (BASE_PREMIUM[item.type] ?? 0) * CURSED_SURCHARGE_RATE;
56	      }
57	    }
58	    let highEnchantmentSurcharge = 0;
59	    for (const item of step.items) {
60	      if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
61	        highEnchantmentSurcharge += (BASE_PREMIUM[item.type] ?? 0) * HIGH_ENCHANTMENT_RATE;
62	      }
63	    }
64	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
65	    const rawPremium = basePremium + cursedSurcharge + highEnchantmentSurcharge + firstInsurance + PROCESSING_FEE;
66	    const premium = Math.ceil(rawPremium);
67	    return { premium };
68	  });
69	  return { results };
70	}
